#!/usr/bin/env node
import fs from "node:fs";

const generatedPath = "apps/api/internal/openapi/openapi.gen.go";
const source = fs.existsSync(generatedPath)
  ? fs.readFileSync(generatedPath, "utf8")
  : "";
const requiredSnippets = [
  "Code generated by github.com/oapi-codegen/oapi-codegen/v2",
  "type StrictServerInterface interface",
  "func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler",
];
const missing = requiredSnippets.filter((snippet) => !source.includes(snippet));
if (missing.length > 0) {
  console.error(
    "Generated Go OpenAPI strict-server stubs are missing or stale.",
  );
  for (const snippet of missing) console.error(`- missing: ${snippet}`);
  console.error("Run: scripts/generate-go-openapi.py");
  process.exit(1);
}
console.log("Generated Go OpenAPI strict-server stubs present.");
